        println!(
            "{}",
            serde_json::to_string_pretty(&parsed).unwrap_or(content)
        );
    } else {
        // Not valid JSON — print raw
        print!("{}", content);
    }

    Ok(())
}

use anyhow::{bail, Result};

use crate::db::Database;
use crate::shared_writer::SharedWriter;
use crate::utils::format_issue_id;

const VALID_PRIORITIES: [&str; 4] = ["low", "medium", "high", "critical"];

/// Best-effort lock release: tries v2 first, then falls back to v1.
/// Mirrors the helper in `session.rs`.
fn release_lock_best_effort(crosslink_dir: &std::path::Path, issue_id: i64) {
    if let Ok(Some(agent)) = crate::identity::AgentConfig::load(crosslink_dir) {
        if let Ok(sync) = crate::sync::SyncManager::new(crosslink_dir) {
            if sync.is_initialized() {
                if sync.is_v2_layout() {
                    if let Ok(Some(writer)) = SharedWriter::new(crosslink_dir) {
                        if let Err(e) = writer.release_lock_v2(issue_id) {
                            eprintln!(
                                "Warning: Could not release lock on {}: {}",
                                format_issue_id(issue_id),
                                e
                            );
                        }
                    }
                } else if let Err(e) = sync.release_lock(&agent, issue_id, false) {
                    eprintln!(
                        "Warning: Could not release lock on {}: {}",
                        format_issue_id(issue_id),
                        e
                    );
                }
            }
        }
    }
}

/// Built-in issue templates
pub struct Template {
    pub name: &'static str,
    pub priority: &'static str,
    pub label: &'static str,
    pub description_prefix: Option<&'static str>,
}

pub const TEMPLATES: &[Template] = &[
    Template {
        name: "bug",
        priority: "high",
        label: "bug",
        description_prefix: Some("Steps to reproduce:\n1. \n\nExpected: \nActual: "),
    },
    Template {
        name: "feature",
        priority: "medium",
        label: "feature",
        description_prefix: Some("Goal: \n\nAcceptance criteria:\n- "),
    },
    Template {
        name: "refactor",
        priority: "low",
        label: "refactor",
        description_prefix: Some("Current state: \n\nDesired state: \n\nReason: "),
    },
    Template {
        name: "research",
        priority: "low",
        label: "research",
        description_prefix: Some("Question: \n\nContext: \n\nFindings: "),
    },
    Template {
        name: "audit",
        priority: "high",
        label: "audit",
        description_prefix: Some("Scope: \n\nFiles to review: \n\nFindings: \n\nSeverity: "),
    },
    Template {
        name: "continuation",
        priority: "high",
        label: "continuation",
        description_prefix: Some("Previous session: \n\nCompleted: \n\nRemaining: \n\nBlockers: "),
    },
    Template {
        name: "investigation",
        priority: "medium",
        label: "investigation",
        description_prefix: Some(
            "Symptom: \n\nReproduction: \n\nHypotheses: \n\nRoot cause: \n\nFix: ",
        ),
    },
];

pub fn get_template(name: &str) -> Option<&'static Template> {
    TEMPLATES.iter().find(|t| t.name == name)
}

pub fn list_templates() -> Vec<&'static str> {
    TEMPLATES.iter().map(|t| t.name).collect()
}

pub fn validate_priority(priority: &str) -> bool {
    VALID_PRIORITIES.contains(&priority)
}

/// Options shared by create and subissue commands.
pub struct CreateOpts<'a> {
    pub labels: &'a [String],
    pub work: bool,
    pub quiet: bool,
    /// If set, lock enforcement is checked when --work is used.
    pub crosslink_dir: Option<&'a std::path::Path>,
    /// Skip compaction after creation (batch mode — display ID assigned on next compaction).
    pub defer_id: bool,
}

pub fn run(
    db: &Database,
    writer: Option<&SharedWriter>,
    title: &str,
    description: Option<&str>,
    priority: &str,
    template: Option<&str>,
    opts: &CreateOpts<'_>,
) -> Result<()> {
    // Apply template if specified
    let (final_priority, final_description, template_label) = if let Some(tmpl_name) = template {
        let tmpl = get_template(tmpl_name).ok_or_else(|| {
            anyhow::anyhow!(
                "Unknown template '{}'. Available: {}",
                tmpl_name,
                list_templates().join(", ")
            )
        })?;

        // Template priority is default, user can override
        let priority = if priority != "medium" {
            priority
        } else {
            tmpl.priority
        };

        // Combine template description prefix with user description
        let desc = match (tmpl.description_prefix, description) {
            (Some(prefix), Some(user_desc)) => Some(format!("{}\n\n{}", prefix, user_desc)),
            (Some(prefix), None) => Some(prefix.to_string()),
            (None, user_desc) => user_desc.map(|s| s.to_string()),
        };

        (priority.to_string(), desc, Some(tmpl.label))
    } else {
        (
            priority.to_string(),
            description.map(|s| s.to_string()),
            None,
        )
    };

    if !validate_priority(&final_priority) {
        bail!(
            "Invalid priority '{}'. Must be one of: {}",
            final_priority,
            VALID_PRIORITIES.join(", ")
        );
    }

    let id = if let Some(w) = writer {
        let id = w.create_issue(db, title, final_description.as_deref(), &final_priority)?;

        // Auto-add label from template
        if let Some(lbl) = template_label {
            w.add_label(db, id, lbl)?;
        }

        // Add user-specified labels
        for lbl in opts.labels {
            w.add_label(db, id, lbl)?;
        }

        id
    } else {
        // Wrap create + labels in a transaction so a label failure
        // doesn't leave an issue without its labels.
        db.transaction(|| {
            let id = db.create_issue(title, final_description.as_deref(), &final_priority)?;

            // Auto-add label from template
            if let Some(lbl) = template_label {
                db.add_label(id, lbl)?;
            }

            // Add user-specified labels
            for lbl in opts.labels {
                db.add_label(id, lbl)?;
            }

            Ok(id)
        })?
    };

    if opts.defer_id && !opts.quiet {
        println!(
            "Created issue {} (display ID deferred — assigned on next compaction)",
            format_issue_id(id)
        );
    } else if opts.quiet {
        println!("{}", id);
    } else {
        println!("Created issue {}", format_issue_id(id));
        if let Some(tmpl) = template {
            println!("  Applied template: {}", tmpl);
        }
    }

    // Set as active session work item
    if opts.work {
        let mut freshly_claimed = false;

        // Check lock status before allowing work on this issue
        if let Some(dir) = opts.crosslink_dir {
            crate::lock_check::enforce_lock(dir, id, db)?;

            // Auto-claim lock in multi-agent mode (same as session work)
            if let Ok(Some(agent)) = crate::identity::AgentConfig::load(dir) {
                if let Ok(sync) = crate::sync::SyncManager::new(dir) {
                    if sync.is_initialized() {
                        if sync.is_v2_layout() {
                            if let Ok(Some(writer)) = SharedWriter::new(dir) {
                                match writer.claim_lock_v2(id, None) {
                                    Ok(crate::shared_writer::LockClaimResult::Claimed) => {
                                        freshly_claimed = true;
                                        if !opts.quiet {
                                            println!(
                                                "Auto-claimed lock on issue {}",
                                                format_issue_id(id)
                                            );
                                        }
                                    }
                                    Ok(crate::shared_writer::LockClaimResult::AlreadyHeld) => {}
                                    Ok(crate::shared_writer::LockClaimResult::Contended {
                                        winner_agent_id,
                                    }) => {
                                        eprintln!(
                                            "Warning: Lock on {} won by '{}'",
                                            format_issue_id(id),
                                            winner_agent_id
                                        );
                                    }
                                    Err(e) => {
                                        eprintln!("Warning: Could not auto-claim lock: {}", e)
                                    }
                                }
                            }
                        } else {
                            match sync.claim_lock(&agent, id, None, false) {
                                Ok(true) => {
                                    freshly_claimed = true;
                                    if !opts.quiet {
                                        println!(
                                            "Auto-claimed lock on issue {}",
                                            format_issue_id(id)
                                        );
                                    }
                                }
                                Ok(false) => {}
                                Err(e) => eprintln!("Warning: Could not auto-claim lock: {}", e),
                            }
                        }
                    }
                }
            }
        }
        let agent_id = opts.crosslink_dir.and_then(|dir| {
            crate::identity::AgentConfig::load(dir)
                .ok()
                .flatten()
                .map(|a| a.agent_id)
        });
        if let Ok(Some(session)) = db.get_current_session_for_agent(agent_id.as_deref()) {
            // If set_session_issue fails after we claimed a lock, release the lock
            // to avoid orphaned locks.
            if let Err(e) = db.set_session_issue(session.id, id) {
                if freshly_claimed {
                    if let Some(dir) = opts.crosslink_dir {
                        release_lock_best_effort(dir, id);
                    }
                }
                return Err(e);
            }
            if !opts.quiet {
                println!("Now working on: {} {}", format_issue_id(id), title);
            }
        } else if !opts.quiet {
            eprintln!("Warning: --work specified but no active session");
        }
    }

    Ok(())
}

pub fn run_subissue(
    db: &Database,
    writer: Option<&SharedWriter>,
    parent_id: i64,
    title: &str,
    description: Option<&str>,
    priority: &str,
    opts: &CreateOpts<'_>,
) -> Result<()> {
    if !validate_priority(priority) {
        bail!(
            "Invalid priority '{}'. Must be one of: {}",
            priority,
            VALID_PRIORITIES.join(", ")
        );
    }

    // Verify parent exists
    let parent = db.get_issue(parent_id)?;
    if parent.is_none() {
        bail!("Parent issue {} not found", format_issue_id(parent_id));
    }

    let id = if let Some(w) = writer {
        let id = w.create_subissue(db, parent_id, title, description, priority)?;

        // Add user-specified labels
        for lbl in opts.labels {
            w.add_label(db, id, lbl)?;
        }

        id
    } else {
        // Wrap create + labels in a transaction so a label failure
        // doesn't leave a subissue without its labels.
        db.transaction(|| {
            let id = db.create_subissue(parent_id, title, description, priority)?;

            // Add user-specified labels
            for lbl in opts.labels {
                db.add_label(id, lbl)?;
            }

            Ok(id)
        })?
    };

    if opts.quiet {
        println!("{}", id);
    } else {
        println!(
            "Created subissue {} under {}",
            format_issue_id(id),
            format_issue_id(parent_id)
        );
    }

    // Set as active session work item
    if opts.work {
        let mut freshly_claimed = false;

        // Check lock status before allowing work on this issue
        if let Some(dir) = opts.crosslink_dir {
            crate::lock_check::enforce_lock(dir, id, db)?;

            // Auto-claim lock in multi-agent mode (same as session work)
            if let Ok(Some(agent)) = crate::identity::AgentConfig::load(dir) {
                if let Ok(sync) = crate::sync::SyncManager::new(dir) {
                    if sync.is_initialized() {
                        if sync.is_v2_layout() {
                            if let Ok(Some(writer)) = SharedWriter::new(dir) {
                                match writer.claim_lock_v2(id, None) {
                                    Ok(crate::shared_writer::LockClaimResult::Claimed) => {
                                        freshly_claimed = true;
                                        if !opts.quiet {
                                            println!(
                                                "Auto-claimed lock on issue {}",
                                                format_issue_id(id)
                                            );
                                        }
                                    }
                                    Ok(crate::shared_writer::LockClaimResult::AlreadyHeld) => {}
                                    Ok(crate::shared_writer::LockClaimResult::Contended {
                                        winner_agent_id,
                                    }) => {
                                        eprintln!(
                                            "Warning: Lock on {} won by '{}'",
                                            format_issue_id(id),
                                            winner_agent_id
                                        );
                                    }
                                    Err(e) => {
                                        eprintln!("Warning: Could not auto-claim lock: {}", e)
                                    }
                                }
                            }
                        } else {
                            match sync.claim_lock(&agent, id, None, false) {
                                Ok(true) => {
                                    freshly_claimed = true;
                                    if !opts.quiet {
                                        println!(
                                            "Auto-claimed lock on issue {}",
                                            format_issue_id(id)
                                        );
                                    }
                                }
                                Ok(false) => {}
                                Err(e) => eprintln!("Warning: Could not auto-claim lock: {}", e),
                            }
                        }
                    }
                }
            }
        }
        let agent_id = opts.crosslink_dir.and_then(|dir| {
            crate::identity::AgentConfig::load(dir)
                .ok()
                .flatten()
                .map(|a| a.agent_id)
        });
        if let Ok(Some(session)) = db.get_current_session_for_agent(agent_id.as_deref()) {
            // If set_session_issue fails after we claimed a lock, release the lock
            // to avoid orphaned locks.
            if let Err(e) = db.set_session_issue(session.id, id) {
                if freshly_claimed {
                    if let Some(dir) = opts.crosslink_dir {
                        release_lock_best_effort(dir, id);
                    }
                }
                return Err(e);
            }
            if !opts.quiet {
                println!("Now working on: {} {}", format_issue_id(id), title);
            }
        } else if !opts.quiet {
            eprintln!("Warning: --work specified but no active session");
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
