            for _ in 0..iterations {
                start(&db, _dir.path()).unwrap();
                prop_assert!(db.get_current_session().unwrap().is_some());
                end(&db, None, _dir.path()).unwrap();
                prop_assert!(db.get_current_session().unwrap().is_none());
