//! Offline issue promotion and local reference rewriting.

use anyhow::Result;
use std::cell::Cell;
use uuid::Uuid;

use crate::db::Database;
use crate::issue_file::read_issue_file;

use super::core::{PushOutcome, SharedWriter, WriteSet};

/// Stats from rewriting local issue references after promotion.
#[derive(Debug, Default)]
pub struct RewriteStats {
    pub comments_updated: usize,
    pub descriptions_updated: usize,
    pub sessions_updated: usize,
}

impl RewriteStats {
    pub fn total(&self) -> usize {
        self.comments_updated + self.descriptions_updated + self.sessions_updated
    }
}

/// Replace `Lx` tokens in text with their promoted `#N` equivalents.
///
/// Only replaces at word boundaries to avoid false positives (e.g. "FILE1" is not rewritten).
/// Returns `Some(new_text)` if any replacements were made, `None` otherwise.
pub(super) fn replace_local_refs(text: &str, replacements: &[(String, String)]) -> Option<String> {
    let mut result = text.to_string();
    let mut changed = false;
    for (old, new) in replacements {
        let mut i = 0;
        while let Some(pos) = result[i..].find(old.as_str()) {
            let abs_pos = i + pos;
            let end_pos = abs_pos + old.len();

            // Check word boundary before: must be start of string or non-alphanumeric
            let before_ok = abs_pos == 0 || !result.as_bytes()[abs_pos - 1].is_ascii_alphanumeric();

            // Check word boundary after: must be end of string or non-alphanumeric
            let after_ok =
                end_pos >= result.len() || !result.as_bytes()[end_pos].is_ascii_alphanumeric();

            if before_ok && after_ok {
                result = format!("{}{}{}", &result[..abs_pos], new, &result[end_pos..]);
                changed = true;
                i = abs_pos + new.len();
            } else {
                i = end_pos;
            }
        }
    }
    if changed {
        Some(result)
    } else {
        None
    }
}

impl SharedWriter {
    /// Promote offline issues (`display_id: null`) to real display IDs.
    ///
    /// Called during sync when connectivity is restored. Scans the cache for
    /// issue files created by this agent with null display_id, bulk-claims
    /// N sequential IDs, rewrites the JSON files, and pushes.
    ///
    /// Returns a vec of `(old_negative_id, new_display_id, title)` for output.
    pub fn promote_offline_issues(&self, db: &Database) -> Result<Vec<(i64, i64, String)>> {
        let offline = self.find_offline_issues()?;
        if offline.is_empty() {
            return Ok(vec![]);
        }

        let count = offline.len() as i64;

        // Build uuid -> negative_id from current SQLite state
        let mut uuid_to_neg_id = std::collections::HashMap::new();
        for issue in &offline {
            if let Ok(neg_id) = db.get_issue_id_by_uuid(&issue.uuid.to_string()) {
                uuid_to_neg_id.insert(issue.uuid, neg_id);
            }
        }

        let offline_info: Vec<(Uuid, String)> =
            offline.iter().map(|i| (i.uuid, i.title.clone())).collect();

        let first_id = Cell::new(0i64);

        let outcome = self.write_commit_push(
            |writer| {
                let (start_id, counters) = writer.claim_display_id(count)?;
                first_id.set(start_id);

                let mut files = Vec::new();
                for (i, (uuid, _)) in offline_info.iter().enumerate() {
                    let path = writer.issue_path(uuid);
                    let mut issue = read_issue_file(&path)?;
                    issue.display_id = Some(start_id + i as i64);
                    let json = serde_json::to_vec_pretty(&issue)?;
                    files.push((format!("issues/{}.json", uuid), json));
                }

                Ok(WriteSet {
                    files,
                    counters: Some(counters),
                    use_git_rm: false,
                })
            },
            &format!("promote {} offline issue(s)", count),
        )?;

        if outcome == PushOutcome::LocalOnly {
            // Still offline -- revert display_id assignments
            for (uuid, _) in &offline_info {
                let path = self.issue_path(uuid);
                if let Ok(mut issue) = read_issue_file(&path) {
                    issue.display_id = None;
                    if let Ok(json) = serde_json::to_string_pretty(&issue) {
                        // INTENTIONAL: reverting display_id on disk is best-effort — offline issues will be re-assigned on next push
                        let _ = std::fs::write(&path, json);
                    }
                }
            }
            // Revert counter
            if let Ok(mut counters) = self.read_counters() {
                counters.next_display_id -= count;
                // INTENTIONAL: counter revert is best-effort — counters will be corrected on next push
                let _ = self.write_counters_to_cache(&counters);
            }
            // Amend the commit to reflect reverted state
            if let Err(e) = self.git_in_cache(&["add", "."]) {
                eprintln!("Warning: failed to stage reverted state: {}", e);
            }
            if let Err(e) = self.git_in_cache(&["commit", "--amend", "--no-edit"]) {
                eprintln!("Warning: failed to commit reverted state: {}", e);
                // INTENTIONAL: last-resort dirty state cleanup is best-effort — prevents poisoning future syncs
                let _ = self.sync.clean_dirty_state();
            }
            return Ok(vec![]);
        }

        // Re-hydrate with new positive IDs
        self.hydrate_with_retry(db)?;

        // Record promoted UUIDs so they are never re-promoted (gh#313).
        let promoted_uuids: Vec<Uuid> = offline_info.iter().map(|(uuid, _)| *uuid).collect();
        if let Err(e) = self.record_promoted_uuids(&promoted_uuids) {
            eprintln!("Warning: failed to record promoted UUIDs: {}", e);
        }

        let start_id = first_id.get();
        let mapping: Vec<(i64, i64, String)> = offline_info
            .iter()
            .enumerate()
            .map(|(i, (uuid, title))| {
                let neg_id = uuid_to_neg_id.get(uuid).copied().unwrap_or(0);
                let new_id = start_id + i as i64;
                (neg_id, new_id, title.clone())
            })
            .collect();

        Ok(mapping)
    }

    /// Rewrite `Lx` references in comments, descriptions, and session notes
    /// after offline issues have been promoted to real display IDs.
    ///
    /// Returns stats on how many text fields were updated.
    pub fn rewrite_local_references(
        &self,
        db: &Database,
        mapping: &[(i64, i64, String)],
    ) -> Result<RewriteStats> {
        if mapping.is_empty() {
            return Ok(RewriteStats::default());
        }

        // Build replacement map: "L1" -> "#5", "L2" -> "#6"
        let replacements: Vec<(String, String)> = mapping
            .iter()
            .filter(|(neg_id, _, _)| *neg_id != 0)
            .map(|(neg_id, new_id, _)| {
                (
                    format!("L{}", neg_id.unsigned_abs()),
                    format!("#{}", new_id),
                )
            })
            .collect();

        if replacements.is_empty() {
            return Ok(RewriteStats::default());
        }

        let mut stats = RewriteStats::default();

        // 1. Rewrite comments and descriptions in JSON files + SQLite
        let mut json_changed = false;
        for (_, new_id, _) in mapping {
            // Update comments in SQLite
            let comments = db.get_comments(*new_id)?;
            for comment in &comments {
                if let Some(new_content) = replace_local_refs(&comment.content, &replacements) {
                    db.update_comment_content(comment.id, &new_content)?;
                    stats.comments_updated += 1;
                }
            }

            // Update description in SQLite
            if let Ok(Some(issue)) = db.get_issue(*new_id) {
                if let Some(ref desc) = issue.description {
                    if let Some(new_desc) = replace_local_refs(desc, &replacements) {
                        db.update_issue(*new_id, None, Some(&new_desc), None)?;
                        stats.descriptions_updated += 1;
                    }
                }
            }
        }

        // Update JSON files on coordination branch
        for (_, new_id, _) in mapping {
            let issue_file = match self.load_issue_by_display_id(*new_id) {
                Ok(f) => f,
                Err(_) => continue,
            };

            let mut changed = false;
            let mut updated_issue = issue_file.clone();

            // Rewrite comments in JSON
            for comment in &mut updated_issue.comments {
                if let Some(new_content) = replace_local_refs(&comment.content, &replacements) {
                    comment.content = new_content;
                    changed = true;
                }
            }

            // Rewrite description in JSON
            if let Some(ref desc) = updated_issue.description {
                if let Some(new_desc) = replace_local_refs(desc, &replacements) {
                    updated_issue.description = Some(new_desc);
                    changed = true;
                }
            }

            if changed {
                let json = serde_json::to_string_pretty(&updated_issue)?;
                let path = self.issue_path(&updated_issue.uuid);
                std::fs::write(&path, json)?;
                json_changed = true;
            }
        }

        // Commit JSON changes if any
        if json_changed {
            if let Err(e) = self.git_in_cache(&["add", "issues/"]) {
                eprintln!("Warning: failed to stage rewritten references: {}", e);
            }
            if let Err(e) = self.git_in_cache(&[
                "commit",
                "-m",
                &format!(
                    "{}: rewrite local references after promotion",
                    self.agent.agent_id
                ),
            ]) {
                eprintln!("Warning: failed to commit rewritten references: {}", e);
            }
            // INTENTIONAL: push is best-effort — rewritten references will be pushed on next sync
            let _ = self.git_in_cache(&["push", self.sync.remote(), crate::sync::HUB_BRANCH]);
        }

        // 2. Rewrite session notes in SQLite
        let sessions = db.get_all_sessions_with_notes()?;
        for session in &sessions {
            if let Some(ref notes) = session.handoff_notes {
                if let Some(new_notes) = replace_local_refs(notes, &replacements) {
                    db.update_session_notes(session.id, &new_notes)?;
                    stats.sessions_updated += 1;
                }
            }
        }

        Ok(stats)
    }
}

use anyhow::{bail, Context, Result};
use chrono::Utc;

use super::core::SyncManager;
use super::HUB_BRANCH;
use crate::identity::AgentConfig;
use crate::locks::Heartbeat;

impl SyncManager {
    /// Write and optionally push a heartbeat file for this agent.
    pub fn push_heartbeat(&self, agent: &AgentConfig, active_issue_id: Option<i64>) -> Result<()> {
        let heartbeat = Heartbeat {
            agent_id: agent.agent_id.clone(),
            last_heartbeat: Utc::now(),
            active_issue_id,
            machine_id: agent.machine_id.clone(),
        };

        // Ensure heartbeats directory exists
        let hb_dir = self.cache_dir.join("heartbeats");
        std::fs::create_dir_all(&hb_dir)?;

        let filename = format!("{}.json", agent.agent_id);
        let path = hb_dir.join(&filename);
        let json = serde_json::to_string_pretty(&heartbeat)?;
        std::fs::write(&path, json)?;

        // Stage the heartbeat file
        self.git_in_cache(&["add", &format!("heartbeats/{}", filename)])?;

        // Commit (may fail if nothing changed, that's fine)
        let msg = format!(
            "heartbeat: {} at {}",
            agent.agent_id,
            Utc::now().format("%Y-%m-%dT%H:%M:%SZ")
        );
        let commit_result = self.git_in_cache(&["commit", "-m", &msg]);
        if let Err(e) = &commit_result {
            let err_str = e.to_string();
            if err_str.contains("nothing to commit") || err_str.contains("no changes added") {
                return Ok(());
            }
            commit_result?;
        }

        // Push (best-effort — may fail if offline or conflicts)
        let push_result = self.git_in_cache(&["push", &self.remote, HUB_BRANCH]);
        if let Err(e) = &push_result {
            let err_str = e.to_string();
            if err_str.contains("Could not resolve host")
                || err_str.contains("Could not read from remote")
            {
                eprintln!("Warning: heartbeat push failed (offline), changes saved locally only");
                return Ok(());
            }
            // If push is rejected (conflict), clean dirty state and try pull+push once
            if err_str.contains("rejected") || err_str.contains("non-fast-forward") {
                // Bail if local has diverged too far — sign of a rebase loop
                self.check_divergence()?;

                // INTENTIONAL: dirty state cleanup and pull are best-effort — heartbeat retry will try again next interval
                let _ = self.clean_dirty_state();
                let _ = self.git_in_cache(&["pull", "--rebase", &self.remote, HUB_BRANCH]);
                if let Err(retry_err) = self.git_in_cache(&["push", &self.remote, HUB_BRANCH]) {
                    eprintln!(
                        "Warning: heartbeat push failed after retry (conflict), changes saved locally only: {}",
                        retry_err
                    );
                }
            }
        }

        Ok(())
    }

    /// Read all heartbeat files from the V1 cache (`heartbeats/` directory).
    pub fn read_heartbeats(&self) -> Result<Vec<Heartbeat>> {
        let dir = self.cache_dir.join("heartbeats");
        if !dir.exists() {
            return Ok(Vec::new());
        }
        let mut heartbeats = Vec::new();
        for entry in std::fs::read_dir(&dir)? {
            let entry = entry?;
            let path = entry.path();
            if path.extension().map(|e| e == "json").unwrap_or(false) {
                let content = std::fs::read_to_string(&path)?;
                if let Ok(hb) = serde_json::from_str::<Heartbeat>(&content) {
                    heartbeats.push(hb);
                }
            }
        }
        Ok(heartbeats)
    }

    /// Read heartbeats from the V2 layout (`agents/{id}/heartbeat.json`).
    ///
    /// V2 heartbeat files use `timestamp` (RFC 3339) instead of `last_heartbeat`,
    /// and may lack `active_issue_id` / `machine_id`. This method converts them
    /// into the common `Heartbeat` struct.
    pub fn read_heartbeats_v2(&self) -> Result<Vec<Heartbeat>> {
        let agents_dir = self.cache_dir.join("agents");
        if !agents_dir.exists() {
            return Ok(Vec::new());
        }
        let mut heartbeats = Vec::new();
        for entry in std::fs::read_dir(&agents_dir)? {
            let entry = entry?;
            if !entry.file_type()?.is_dir() {
                continue;
            }
            let agent_id = entry.file_name().to_string_lossy().to_string();
            let hb_path = entry.path().join("heartbeat.json");
            if !hb_path.exists() {
                continue;
            }
            let content = match std::fs::read_to_string(&hb_path) {
                Ok(c) => c,
                Err(_) => continue,
            };
            // Try native Heartbeat format first, then V2 JSON format
            if let Ok(hb) = serde_json::from_str::<Heartbeat>(&content) {
                heartbeats.push(hb);
            } else if let Ok(val) = serde_json::from_str::<serde_json::Value>(&content) {
                let timestamp = val
                    .get("timestamp")
                    .and_then(|t| t.as_str())
                    .and_then(|ts| chrono::DateTime::parse_from_rfc3339(ts).ok())
                    .map(|dt| dt.with_timezone(&Utc))
                    .unwrap_or_else(Utc::now);
                let active_issue_id = val.get("active_issue_id").and_then(|v| v.as_i64());
                let machine_id = val
                    .get("machine_id")
                    .and_then(|v| v.as_str())
                    .unwrap_or_default()
                    .to_string();
                heartbeats.push(Heartbeat {
                    agent_id,
                    last_heartbeat: timestamp,
                    active_issue_id,
                    machine_id,
                });
            }
        }
        Ok(heartbeats)
    }

    /// Read heartbeats using the appropriate method based on hub layout version.
    ///
    /// V1: reads `heartbeats/*.json`
    /// V2: reads `agents/*/heartbeat.json`, merged with any V1 heartbeats
    pub fn read_heartbeats_auto(&self) -> Result<Vec<Heartbeat>> {
        let mut heartbeats = self.read_heartbeats()?;
        if self.is_v2_layout() {
            let v2 = self.read_heartbeats_v2()?;
            // Merge V2 heartbeats, preferring the one with the most recent timestamp
            use std::collections::HashMap;
            let mut by_agent: HashMap<String, Heartbeat> = HashMap::new();
            for hb in heartbeats.into_iter().chain(v2) {
                by_agent
                    .entry(hb.agent_id.clone())
                    .and_modify(|existing| {
                        if hb.last_heartbeat > existing.last_heartbeat {
                            *existing = hb.clone();
                        }
                    })
                    .or_insert(hb);
            }
            heartbeats = by_agent.into_values().collect();
        }
        Ok(heartbeats)
    }

    /// Create the agent directory on the hub branch if it doesn't exist.
    ///
    /// Creates `agents/{agent_id}/heartbeat.json` with an initial heartbeat.
    /// Returns `Ok(true)` if the directory was created, `Ok(false)` if it already existed.
    pub fn ensure_agent_dir(&self, agent_id: &str) -> Result<bool> {
        if !self.create_agent_dir_files(agent_id)? {
            return Ok(false);
        }

        // Stage and commit
        self.git_in_cache(&["add", &format!("agents/{}/heartbeat.json", agent_id)])?;
        self.git_in_cache(&[
            "commit",
            "-m",
            &format!("bootstrap: initialize agent directory for {}", agent_id),
        ])?;

        // Push with retry on rebase conflict
        for attempt in 0..3 {
            let push_result = self.git_in_cache(&["push", &self.remote, HUB_BRANCH]);
            match push_result {
                Ok(_) => return Ok(true),
                Err(e) => {
                    let err_str = e.to_string();
                    if err_str.contains("Could not resolve host")
                        || err_str.contains("Could not read from remote")
                    {
                        return Ok(true); // Offline — commit is local
                    }
                    if err_str.contains("rejected") || err_str.contains("non-fast-forward") {
                        if attempt < 2 {
                            // Bail if local has diverged too far — sign of a rebase loop
                            self.check_divergence()?;
                            // INTENTIONAL: pull/rebase failure is non-fatal — retry loop will bail on persistent conflicts
                            let _ =
                                self.git_in_cache(&["pull", "--rebase", &self.remote, HUB_BRANCH]);
                            continue;
                        }
                        bail!("Push failed after 3 retries for agent dir {}", agent_id);
                    }
                    return Err(e);
                }
            }
        }

        Ok(true)
    }

    /// Create the agent directory and heartbeat file on disk (no git ops).
    ///
    /// Returns `Ok(true)` if created, `Ok(false)` if the directory already exists.
    pub(super) fn create_agent_dir_files(&self, agent_id: &str) -> Result<bool> {
        let agents_dir = self.cache_dir.join("agents").join(agent_id);
        if agents_dir.exists() {
            return Ok(false);
        }

        std::fs::create_dir_all(&agents_dir)
            .with_context(|| format!("Failed to create agent directory for {}", agent_id))?;

        // Write initial heartbeat
        let heartbeat = serde_json::json!({
            "agent_id": agent_id,
            "timestamp": chrono::Utc::now().to_rfc3339(),
            "status": "active"
        });
        let heartbeat_path = agents_dir.join("heartbeat.json");
        std::fs::write(&heartbeat_path, serde_json::to_string_pretty(&heartbeat)?)
            .with_context(|| "Failed to write initial heartbeat")?;

        Ok(true)
    }
}

// E-ana tablet — prune command: squash hub/knowledge branch history for storage efficiency
use anyhow::{bail, Context, Result};
use serde::Serialize;
use std::path::Path;
use std::process::Command;

use crate::knowledge::KnowledgeManager;
use crate::sync::SyncManager;

/// Options for the prune command.
pub struct PruneOpts {
    pub dry_run: bool,
    pub force: bool,
    pub keep_commits: usize,
    pub hub_only: bool,
    pub knowledge_only: bool,
}

/// Size stats for a branch before/after pruning.
#[derive(Debug, Serialize)]
struct BranchStats {
    branch: String,
    commits_before: usize,
    commits_after: usize,
}

/// Run a git command in the given directory, returning its output.
fn git_in_dir(dir: &Path, args: &[&str]) -> Result<std::process::Output> {
    let output = Command::new("git")
        .current_dir(dir)
        .args(args)
        .output()
        .with_context(|| format!("Failed to run git {:?} in {}", args, dir.display()))?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!(
            "git {:?} in {} failed: {}",
            args,
            dir.display(),
            stderr.trim()
        );
    }
    Ok(output)
}

/// Count the number of commits on the current branch in a worktree.
fn count_commits(cache_dir: &Path) -> Result<usize> {
    let output = git_in_dir(cache_dir, &["rev-list", "--count", "HEAD"])?;
    let count_str = String::from_utf8_lossy(&output.stdout).trim().to_string();
    count_str
        .parse::<usize>()
        .with_context(|| format!("Failed to parse commit count: {:?}", count_str))
}

/// Remove stale data files from the hub branch cache.
///
/// Cleans up old heartbeat files (V1 layout) and agent directories
/// for decommissioned agents (those with no events).
fn remove_stale_hub_data(cache_dir: &Path) -> Result<Vec<String>> {
    let mut removed = Vec::new();

    // Clean up old V1 heartbeat files
    let heartbeats_dir = cache_dir.join("heartbeats");
    if heartbeats_dir.is_dir() {
        for entry in std::fs::read_dir(&heartbeats_dir)? {
            let entry = entry?;
            if entry.file_type()?.is_file() {
                let name = entry.file_name().to_string_lossy().to_string();
                removed.push(format!("heartbeats/{}", name));
                std::fs::remove_file(entry.path())?;
            }
        }
        // Remove the directory if now empty
        if std::fs::read_dir(&heartbeats_dir)?.next().is_none() {
            std::fs::remove_dir(&heartbeats_dir)?;
        }
    }

    // Clean up agent directories for decommissioned agents
    // (those whose events.log is empty or missing)
    let agents_dir = cache_dir.join("agents");
    if agents_dir.is_dir() {
        for entry in std::fs::read_dir(&agents_dir)? {
            let entry = entry?;
            if !entry.file_type()?.is_dir() {
                continue;
            }
            let agent_dir = entry.path();
            let events_log = agent_dir.join("events.log");
            let has_events = events_log.exists()
                && std::fs::metadata(&events_log)
                    .map(|m| m.len() > 0)
                    .unwrap_or(false);

            if !has_events {
                let agent_name = entry.file_name().to_string_lossy().to_string();
                removed.push(format!("agents/{}/", agent_name));
                std::fs::remove_dir_all(&agent_dir)?;
            }
        }
    }

    Ok(removed)
}

/// Count stale data files without removing them (for dry-run).
fn count_stale_hub_data(cache_dir: &Path) -> Vec<String> {
    let mut stale = Vec::new();

    let heartbeats_dir = cache_dir.join("heartbeats");
    if heartbeats_dir.is_dir() {
        if let Ok(entries) = std::fs::read_dir(&heartbeats_dir) {
            for entry in entries.flatten() {
                if entry.file_type().map(|t| t.is_file()).unwrap_or(false) {
                    stale.push(format!(
                        "heartbeats/{}",
                        entry.file_name().to_string_lossy()
                    ));
                }
            }
        }
    }

    let agents_dir = cache_dir.join("agents");
    if agents_dir.is_dir() {
        if let Ok(entries) = std::fs::read_dir(&agents_dir) {
            for entry in entries.flatten() {
                if !entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
                    continue;
                }
                let events_log = entry.path().join("events.log");
                let has_events = events_log.exists()
                    && std::fs::metadata(&events_log)
                        .map(|m| m.len() > 0)
                        .unwrap_or(false);
                if !has_events {
                    stale.push(format!("agents/{}/", entry.file_name().to_string_lossy()));
                }
            }
        }
    }

    stale
}

/// Squash the history of a branch in a cache worktree.
///
/// Creates a new orphan commit (or keeps the last N commits) with the current
/// tree state, then force-updates the branch ref and force-pushes.
fn squash_branch(
    cache_dir: &Path,
    branch: &str,
    remote: &str,
    keep_commits: usize,
    dry_run: bool,
) -> Result<BranchStats> {
    let commits_before = count_commits(cache_dir)?;

    if commits_before <= keep_commits.max(1) {
        return Ok(BranchStats {
            branch: branch.to_string(),
            commits_before,
            commits_after: commits_before,
        });
    }

    if dry_run {
        let commits_after = keep_commits.max(1);
        return Ok(BranchStats {
            branch: branch.to_string(),
            commits_before,
            commits_after,
        });
    }

    let commits_after = if keep_commits <= 1 {
        // Squash everything into a single commit with the current tree.
        // 1. Stage all current content (ensures index matches worktree)
        git_in_dir(cache_dir, &["add", "-A"])?;

        // 2. Write the current index as a tree object
        let tree_output = git_in_dir(cache_dir, &["write-tree"])?;
        let tree_hash = String::from_utf8_lossy(&tree_output.stdout)
            .trim()
            .to_string();

        // 3. Create a root commit (no parent) with this tree
        let commit_output = Command::new("git")
            .current_dir(cache_dir)
            .args([
                "commit-tree",
                &tree_hash,
                "-m",
                &format!(
                    "prune: squash {} history to current state\n\nSquashed {} commit(s).",
                    branch, commits_before
                ),
            ])
            .output()
            .context("Failed to create squash commit")?;

        if !commit_output.status.success() {
            let stderr = String::from_utf8_lossy(&commit_output.stderr);
            bail!("git commit-tree failed: {}", stderr.trim());
        }

        let new_head = String::from_utf8_lossy(&commit_output.stdout)
            .trim()
            .to_string();

        // 4. Update the branch ref to the new root commit
        git_in_dir(
            cache_dir,
            &["update-ref", &format!("refs/heads/{}", branch), &new_head],
        )?;

        // 5. Reset HEAD to the new commit
        git_in_dir(cache_dir, &["reset", "--hard", &new_head])?;

        1
    } else {
        // Keep last N commits: rewrite history preserving recent commits.
        // Find the base commit (Nth from HEAD)
        let base_ref = format!("HEAD~{}", keep_commits);
        let base_hash_output = git_in_dir(cache_dir, &["rev-parse", &base_ref])?;
        let base_hash = String::from_utf8_lossy(&base_hash_output.stdout)
            .trim()
            .to_string();

        // Get the tree at the base commit
        let tree_output = git_in_dir(
            cache_dir,
            &["rev-parse", &format!("{}^{{tree}}", base_hash)],
        )?;
        let tree_hash = String::from_utf8_lossy(&tree_output.stdout)
            .trim()
            .to_string();

        // Create a new root commit with the base tree
        let commit_output = Command::new("git")
            .current_dir(cache_dir)
            .args([
                "commit-tree",
                &tree_hash,
                "-m",
                &format!(
                    "prune: squash {} history (kept last {} commits)\n\nSquashed {} commit(s).",
                    branch,
                    keep_commits,
                    commits_before - keep_commits
                ),
            ])
            .output()
            .context("Failed to create base squash commit")?;

        if !commit_output.status.success() {
            let stderr = String::from_utf8_lossy(&commit_output.stderr);
            bail!("git commit-tree failed: {}", stderr.trim());
        }

        let new_base = String::from_utf8_lossy(&commit_output.stdout)
            .trim()
            .to_string();

        // Save current tip
        let tip_output = git_in_dir(cache_dir, &["rev-parse", "HEAD"])?;
        let tip_hash = String::from_utf8_lossy(&tip_output.stdout)
            .trim()
            .to_string();

        // Detach, reset to new base, cherry-pick the kept commits
        git_in_dir(cache_dir, &["checkout", "--detach", "HEAD"])?;
        git_in_dir(cache_dir, &["reset", "--hard", &new_base])?;

        // Get list of commits to replay (oldest first)
        let range = format!("{}..{}", base_hash, tip_hash);
        let log_output = git_in_dir(cache_dir, &["rev-list", "--reverse", &range])?;
        let log_text = String::from_utf8_lossy(&log_output.stdout)
            .trim()
            .to_string();

        for commit_hash in log_text.lines() {
            if !commit_hash.is_empty() {
                git_in_dir(cache_dir, &["cherry-pick", commit_hash])?;
            }
        }

        // Update the branch ref to point to the new history
        let new_tip_output = git_in_dir(cache_dir, &["rev-parse", "HEAD"])?;
        let new_tip = String::from_utf8_lossy(&new_tip_output.stdout)
            .trim()
            .to_string();
        git_in_dir(
            cache_dir,
            &["update-ref", &format!("refs/heads/{}", branch), &new_tip],
        )?;
        git_in_dir(cache_dir, &["checkout", branch])?;

        keep_commits + 1 // base squash commit + kept commits
    };

    // Force-push the rewritten branch
    let refspec = format!("{}:{}", branch, branch);
    git_in_dir(cache_dir, &["push", "--force", remote, &refspec])?;

    Ok(BranchStats {
        branch: branch.to_string(),
        commits_before,
        commits_after,
    })
}

/// Entry point for `crosslink prune`.
pub fn run(crosslink_dir: &Path, opts: &PruneOpts, json: bool) -> Result<()> {
    if !opts.force && !opts.dry_run {
        eprintln!("Warning: This will rewrite branch history and force-push.");
        eprintln!("Use --force to confirm, or --dry-run to preview.");
        return Ok(());
    }

    let mut results: Vec<BranchStats> = Vec::new();
    let mut stale_removed: Vec<String> = Vec::new();

    // --- Hub branch ---
    if !opts.knowledge_only {
        let sync = SyncManager::new(crosslink_dir)?;
        sync.init_cache()?;
        sync.fetch()?;

        let cache_dir = sync.cache_path();

        if opts.dry_run {
            stale_removed = count_stale_hub_data(cache_dir);
        } else {
            let removed = remove_stale_hub_data(cache_dir)?;
            if !removed.is_empty() {
                // INTENTIONAL: staging is best-effort — we check for actual changes before committing
                let _ = git_in_dir(cache_dir, &["add", "-A"]);
                let has_changes = git_in_dir(cache_dir, &["diff", "--cached", "--quiet"]).is_err();
                if has_changes {
                    git_in_dir(cache_dir, &["commit", "-m", "prune: remove stale hub data"])?;
                }
                stale_removed = removed;
            }
        }

        let stats = squash_branch(
            cache_dir,
            "crosslink/hub",
            sync.remote(),
            opts.keep_commits,
            opts.dry_run,
        )?;
        results.push(stats);
    }

    // --- Knowledge branch ---
    if !opts.hub_only {
        let km = KnowledgeManager::new(crosslink_dir)?;
        if km.is_initialized() {
            km.init_cache()?;
            km.sync()?;

            let cache_dir = km.cache_path();
            let remote = crate::sync::read_tracker_remote(km.crosslink_dir());

            let stats = squash_branch(
                cache_dir,
                "crosslink/knowledge",
                &remote,
                opts.keep_commits,
                opts.dry_run,
            )?;
            results.push(stats);
        } else {
            eprintln!("Knowledge branch not initialized, skipping.");
        }
    }

    // --- Output ---
    if json {
        #[derive(Serialize)]
        struct PruneReport {
            branches: Vec<BranchStats>,
            stale_data_removed: Vec<String>,
            dry_run: bool,
        }
        let report = PruneReport {
            branches: results,
            stale_data_removed: stale_removed,
            dry_run: opts.dry_run,
        };
        println!("{}", serde_json::to_string_pretty(&report)?);
        return Ok(());
    }

    // Human-readable output
    if opts.dry_run {
        println!("Prune plan (dry run):\n");
    }

    for stats in &results {
        if stats.commits_before == stats.commits_after {
            println!(
                "  {} — {} commit(s), nothing to prune",
                stats.branch, stats.commits_before
            );
        } else {
            let verb = if opts.dry_run {
                "would remove"
            } else {
                "removed"
            };
            println!(
                "  {} — {} → {} commit(s) ({} {})",
                stats.branch,
                stats.commits_before,
                stats.commits_after,
                stats.commits_before - stats.commits_after,
                verb,
            );
        }
    }

    if !stale_removed.is_empty() {
        println!(
            "\n  Stale data {}: {} file(s)/dir(s)",
            if opts.dry_run { "to remove" } else { "removed" },
            stale_removed.len()
        );
        for item in &stale_removed {
            println!("    {}", item);
        }
    }

    if opts.dry_run {
        println!("\nRun with --force (without --dry-run) to proceed.");
    } else {
        println!("\nDone.");
    }

    Ok(())
}

// E-ana tablet — kickoff launch: agent launch infrastructure
use anyhow::{bail, Context, Result};
use std::path::Path;
use std::process::Command;
use std::time::Duration;

use crate::identity::AgentConfig;

use super::helpers::*;
use super::types::*;

/// Resolve the correct `timeout` command for the current platform.
///
/// On macOS, `timeout` is not available by default. The GNU coreutils
/// package (via Homebrew) installs it as `gtimeout`.
/// Returns the command name to use, or an error with install instructions.
fn resolve_timeout_command(platform: &Platform) -> Result<&'static str> {
    if command_available("timeout") {
        return Ok("timeout");
    }
    if command_available("gtimeout") {
        return Ok("gtimeout");
    }
    bail!(
        "Neither `timeout` nor `gtimeout` found.\n{}",
        install_hint("timeout", platform)
    );
}

/// Read the `sandbox.command` setting from hook-config.json, if configured.
pub(super) fn read_sandbox_command(crosslink_dir: &Path) -> Option<String> {
    let config_path = crosslink_dir.join("hook-config.json");
    let content = std::fs::read_to_string(&config_path).ok()?;
    let parsed: serde_json::Value = serde_json::from_str(&content).ok()?;
    parsed
        .get("sandbox")
        .and_then(|s| s.get("command"))
        .and_then(|v| v.as_str())
        .filter(|s| !s.is_empty())
        .map(|s| s.to_string())
}

pub(super) fn read_watchdog_config(crosslink_dir: &Path) -> WatchdogConfig {
    let config_path = crosslink_dir.join("hook-config.json");
    let content = match std::fs::read_to_string(&config_path) {
        Ok(c) => c,
        Err(_) => return WatchdogConfig::default(),
    };
    let parsed: serde_json::Value = match serde_json::from_str(&content) {
        Ok(v) => v,
        Err(_) => return WatchdogConfig::default(),
    };

    let wd = match parsed.get("watchdog") {
        Some(v) => v,
        None => return WatchdogConfig::default(),
    };

    let mut cfg = WatchdogConfig::default();
    if let Some(v) = wd.get("enabled").and_then(|v| v.as_bool()) {
        cfg.enabled = v;
    }
    if let Some(v) = wd.get("staleness_secs").and_then(|v| v.as_u64()) {
        cfg.staleness_secs = v;
    }
    if let Some(v) = wd.get("max_nudges").and_then(|v| v.as_u64()) {
        cfg.max_nudges = v as u32;
    }
    if let Some(v) = wd.get("check_interval_secs").and_then(|v| v.as_u64()) {
        cfg.check_interval_secs = v;
    }
    if let Some(v) = wd.get("grace_period_secs").and_then(|v| v.as_u64()) {
        cfg.grace_period_secs = v;
    }
    cfg
}

/// Build the watchdog shell script that monitors heartbeat staleness and
/// nudges idle agents by sending "continue" via tmux send-keys.
pub(super) fn build_watchdog_script(
    session_name: &str,
    worktree_dir: &Path,
    cfg: &WatchdogConfig,
) -> String {
    // Use portable stat command — try GNU stat first, fall back to BSD
    format!(
        r#"NUDGES=0
sleep {grace}
while true; do
    sleep {interval}
    if [ -f "{worktree}/.kickoff-status" ]; then exit 0; fi
    if ! tmux has-session -t "{session}" 2>/dev/null; then exit 0; fi
    HB="{worktree}/.crosslink/.cache/last-heartbeat"
    if [ -f "$HB" ]; then
        LAST=$(stat -c %Y "$HB" 2>/dev/null || stat -f %m "$HB" 2>/dev/null)
        NOW=$(date +%s)
        AGE=$((NOW - LAST))
        if [ "$AGE" -gt {staleness} ]; then
            if [ "$NUDGES" -ge {max_nudges} ]; then exit 1; fi
            NUDGES=$((NUDGES + 1))
            tmux send-keys -t "{session}" "continue working, the task is not yet complete" Enter
        fi
    fi
done
"#,
        grace = cfg.grace_period_secs,
        interval = cfg.check_interval_secs,
        worktree = worktree_dir.display(),
        session = session_name,
        staleness = cfg.staleness_secs,
        max_nudges = cfg.max_nudges,
    )
}

/// Spawn a background watchdog process that monitors the agent's heartbeat
/// and sends "continue" to the tmux session if the agent goes idle.
pub(super) fn spawn_watchdog(
    session_name: &str,
    worktree_dir: &Path,
    cfg: &WatchdogConfig,
) -> Result<()> {
    let script = build_watchdog_script(session_name, worktree_dir, cfg);

    Command::new("bash")
        .args(["-c", &script])
        .stdin(std::process::Stdio::null())
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .spawn()
        .context("Failed to spawn watchdog process")?;

    Ok(())
}

/// Build the shell command string for launching a claude agent.
///
/// When `sandbox_command` is set, the claude invocation is wrapped:
/// ```text
/// timeout 3600s my-sandbox --project-dir /path -- env -u CLAUDECODE claude ...
/// ```
/// Without sandbox:
/// ```text
/// timeout 3600s env -u CLAUDECODE claude ...
/// ```
#[allow(clippy::too_many_arguments)]
pub(super) fn build_agent_command(
    timeout_cmd: &str,
    timeout_secs: u64,
    model: &str,
    allowed_tools: &str,
    kickoff_file: &str,
    sandbox_command: Option<&str>,
    worktree_dir: &Path,
    skip_permissions: bool,
) -> String {
    let skip_flag = if skip_permissions {
        " --dangerously-skip-permissions"
    } else {
        ""
    };
    let claude_cmd = format!(
        "env -u CLAUDECODE claude{} --model {} --allowedTools '{}' -- \"$(cat {})\"",
        skip_flag, model, allowed_tools, kickoff_file
    );
    match sandbox_command {
        Some(cmd) => {
            let expanded = cmd.replace("{{worktree}}", &worktree_dir.to_string_lossy());
            format!(
                "{} {}s {} {}",
                timeout_cmd, timeout_secs, expanded, claude_cmd
            )
        }
        None => format!("{} {}s {}", timeout_cmd, timeout_secs, claude_cmd),
    }
}

/// Pre-flight check: verify all required external commands are present before
/// creating worktrees, branches, or sessions. Emits clear errors with install
/// instructions for any missing command.
pub(super) fn preflight_check(
    container: &ContainerMode,
    verify: &VerifyLevel,
    crosslink_dir: &Path,
) -> Result<PreflightResult> {
    let platform = detect_platform();
    let mut missing: Vec<String> = Vec::new();

    // timeout (or gtimeout on macOS) — always required for agent timeout
    let timeout_cmd = match resolve_timeout_command(&platform) {
        Ok(cmd) => cmd,
        Err(e) => {
            missing.push(format!("{}", e));
            "timeout" // placeholder, won't be used since we'll bail
        }
    };

    // tmux — required for local (non-container) mode
    // On Windows, tmux is not available at all — bail early with a clear message.
    if *container == ContainerMode::None {
        if cfg!(target_os = "windows") {
            bail!(
                "Local kickoff mode requires tmux, which is not available on Windows.\n\
                 Use `--container docker` for agent kickoff on Windows."
            );
        }
        if !command_available("tmux") {
            missing.push(install_hint("tmux", &platform));
        }
    }

    // claude CLI — required for local mode
    if *container == ContainerMode::None && !command_available("claude") {
        missing.push(install_hint("claude", &platform));
    }

    // gh — required for CI/thorough verification
    if (*verify == VerifyLevel::Ci || *verify == VerifyLevel::Thorough) && !command_available("gh")
    {
        missing.push(install_hint("gh", &platform));
    }

    // docker/podman — required when using container mode
    match container {
        ContainerMode::Docker if !command_available("docker") => {
            missing.push(install_hint("docker", &platform));
        }
        ContainerMode::Podman if !command_available("podman") => {
            missing.push(install_hint("podman", &platform));
        }
        _ => {}
    }

    // sandbox command — validate the binary exists when configured
    let sandbox_command = read_sandbox_command(crosslink_dir);
    if let Some(ref cmd) = sandbox_command {
        // Extract the binary name (first word before any flags/templates)
        let binary = cmd.split_whitespace().next().unwrap_or(cmd);
        if !command_available(binary) {
            missing.push(format!(
                "`{}` (configured in hook-config.json sandbox.command) not found on PATH",
                binary
            ));
        }
    }

    if !missing.is_empty() {
        let header = format!(
            "Pre-flight check failed — {} missing command{}:\n",
            missing.len(),
            if missing.len() == 1 { "" } else { "s" }
        );
        let body = missing
            .iter()
            .enumerate()
            .map(|(i, msg)| format!("{}. {}", i + 1, msg))
            .collect::<Vec<_>>()
            .join("\n\n");
        bail!("{}{}", header, body);
    }

    Ok(PreflightResult {
        timeout_cmd,
        sandbox_command,
    })
}

/// Get the git repository root.
pub(super) fn repo_root() -> Result<std::path::PathBuf> {
    let output = Command::new("git")
        .args(["rev-parse", "--show-toplevel"])
        .output()
        .context("Failed to run git rev-parse")?;
    if !output.status.success() {
        bail!("Not inside a git repository");
    }
    let path = String::from_utf8_lossy(&output.stdout).trim().to_string();
    Ok(std::path::PathBuf::from(path))
}

/// Create a feature branch and worktree for the agent.
pub(super) fn create_worktree(
    repo_root: &Path,
    slug: &str,
    base_branch: Option<&str>,
) -> Result<(std::path::PathBuf, String)> {
    let branch_name = format!("feature/{}", slug);
    let worktree_dir = repo_root.join(".worktrees").join(slug);

    if worktree_dir.exists() {
        bail!(
            "Worktree already exists at {}. Remove it first or use --branch to target an existing branch.",
            worktree_dir.display()
        );
    }

    // Determine base ref
    let base = base_branch.unwrap_or("HEAD");

    // Create the worktree with a new branch
    let output = Command::new("git")
        .current_dir(repo_root)
        .args(["worktree", "add", "-b", &branch_name])
        .arg(&worktree_dir)
        .arg(base)
        .output()
        .context("Failed to create git worktree")?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!("Failed to create worktree: {}", stderr.trim());
    }

    Ok((worktree_dir, branch_name))
}

/// Initialize crosslink and agent identity in the worktree.
pub(super) fn init_worktree_agent(
    worktree_dir: &Path,
    crosslink_dir: &Path,
    slug: &str,
) -> Result<String> {
    // Run crosslink init --force in the worktree
    let output = Command::new("crosslink")
        .current_dir(worktree_dir)
        .args(["init", "--force", "--skip-signing", "--defaults"])
        .output()
        .context("Failed to run crosslink init in worktree")?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        tracing::warn!("crosslink init in worktree: {}", stderr.trim());
    }

    // Derive agent ID from parent agent or hostname
    let parent_id = AgentConfig::load(crosslink_dir)?
        .map(|c| c.agent_id)
        .unwrap_or_else(|| "driver".to_string());

    let agent_id = format!("{}--{}", parent_id, slug);

    // Initialize agent identity in worktree (skip key gen — inherits from parent)
    let wt_crosslink = worktree_dir.join(".crosslink");
    if wt_crosslink.exists() {
        // Only init if not already configured
        if AgentConfig::load(&wt_crosslink)?.is_none() {
            if let Err(e) = super::super::agent::init(
                &wt_crosslink,
                &agent_id,
                Some(&format!("Kickoff agent for: {}", slug)),
                true, // no-key: inherit parent's key
                false,
            ) {
                eprintln!("Warning: could not initialize agent identity in worktree: {e} — agent will work without its own identity");
            }

            // Copy parent's SSH key info into the new agent config and publish
            // the key under the new agent ID so `crosslink trust approve` can find it.
            if let Some(parent_config) = AgentConfig::load(crosslink_dir)? {
                if let Some(ref public_key) = parent_config.ssh_public_key {
                    if let Ok(Some(mut child_config)) = AgentConfig::load(&wt_crosslink) {
                        child_config.ssh_key_path = parent_config.ssh_key_path.clone();
                        child_config.ssh_fingerprint = parent_config.ssh_fingerprint.clone();
                        child_config.ssh_public_key = Some(public_key.clone());

                        let agent_json = wt_crosslink.join("agent.json");
                        if let Ok(json) = serde_json::to_string_pretty(&child_config) {
                            if let Err(e) = std::fs::write(&agent_json, json) {
                                tracing::warn!("could not write agent config to {}: {e} — agent will use inherited config", agent_json.display());
                            }
                        }

                        // Publish the parent's public key under the new agent ID
                        if let Err(e) = super::super::trust::publish_agent_key(
                            &wt_crosslink,
                            &agent_id,
                            public_key,
                        ) {
                            eprintln!(
                                "Warning: Could not publish key for agent '{}': {}",
                                agent_id, e
                            );
                            eprintln!("Key will be auto-published on next `crosslink sync`.");
                        }
                    }
                }
            }
        }
    }

    // Sync coordination state
    let output = Command::new("crosslink")
        .current_dir(worktree_dir)
        .args(["sync"])
        .output();

    if let Ok(o) = output {
        if !o.status.success() {
            eprintln!("Warning: crosslink sync in worktree returned non-zero");
        }
    }

    Ok(agent_id)
}

/// Exclude kickoff files from git tracking.
pub(super) fn exclude_kickoff_files(worktree_dir: &Path) -> Result<()> {
    let output = Command::new("git")
        .current_dir(worktree_dir)
        .args(["rev-parse", "--git-common-dir"])
        .output()
        .context("Failed to get git common dir")?;

    let common_dir = String::from_utf8_lossy(&output.stdout).trim().to_string();
    let exclude_path = std::path::PathBuf::from(&common_dir).join("info/exclude");

    // Ensure parent directory exists
    if let Some(parent) = exclude_path.parent() {
        std::fs::create_dir_all(parent).ok();
    }

    let existing = std::fs::read_to_string(&exclude_path).unwrap_or_default();
    let additions = missing_exclude_patterns(&existing);

    if !additions.is_empty() {
        use std::io::Write;
        let mut file = std::fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(&exclude_path)
            .context("Failed to open git exclude file")?;
        for pattern in additions {
            writeln!(file, "{}", pattern)?;
        }
    }

    Ok(())
}

/// Launch the agent as a local tmux process.
#[allow(clippy::too_many_arguments)]
pub(super) fn launch_local(
    worktree_dir: &Path,
    session_name: &str,
    model: &str,
    allowed_tools: &str,
    timeout: Duration,
    timeout_cmd: &str,
    sandbox_command: Option<&str>,
    crosslink_dir: &Path,
    skip_permissions: bool,
) -> Result<()> {
    // Create the tmux session
    let output = Command::new("tmux")
        .args([
            "new-session",
            "-d",
            "-s",
            session_name,
            "-c",
            &worktree_dir.to_string_lossy(),
        ])
        .output()
        .context("Failed to create tmux session")?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!("Failed to create tmux session: {}", stderr.trim());
    }

    // Build the claude command (with optional sandbox wrapping)
    let cmd = build_agent_command(
        timeout_cmd,
        timeout.as_secs(),
        model,
        allowed_tools,
        "KICKOFF.md",
        sandbox_command,
        worktree_dir,
        skip_permissions,
    );

    // Write initial status sentinel BEFORE sending the command.
    // This ensures we never have a worktree in limbo with no status.
    std::fs::write(worktree_dir.join(".kickoff-status"), "LAUNCHING\n")
        .context("Failed to write initial .kickoff-status")?;

    // Send the command to the tmux session
    let output = Command::new("tmux")
        .args(["send-keys", "-t", session_name, &cmd, "Enter"])
        .output()
        .context("Failed to send command to tmux session")?;

    if !output.status.success() {
        // INTENTIONAL: status file write is best-effort — used for monitoring, not control flow
        let _ = std::fs::write(worktree_dir.join(".kickoff-status"), "FAILED\n");
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!("Failed to send keys to tmux: {}", stderr.trim());
    }

    // INTENTIONAL: status file write is best-effort — used for monitoring, not control flow
    let _ = std::fs::write(worktree_dir.join(".kickoff-status"), "RUNNING\n");

    // Spawn watchdog sidecar to nudge idle agents
    let watchdog_cfg = read_watchdog_config(crosslink_dir);
    if watchdog_cfg.enabled {
        if let Err(e) = spawn_watchdog(session_name, worktree_dir, &watchdog_cfg) {
            tracing::warn!("failed to spawn watchdog: {}", e);
        }
    }

    Ok(())
}

/// Launch the agent in a Docker or Podman container.
pub(super) fn launch_container(
    runtime: &ContainerMode,
    worktree_dir: &Path,
    image: &str,
    agent_id: &str,
    model: &str,
    allowed_tools: &str,
    timeout: Duration,
) -> Result<String> {
    let runtime_cmd = match runtime {
        ContainerMode::Docker => "docker",
        ContainerMode::Podman => "podman",
        ContainerMode::None => unreachable!(),
    };

    // Check runtime is available
    if !command_available(runtime_cmd) {
        bail!(
            "{} is not installed. Install it or use --container none for local mode.",
            runtime_cmd
        );
    }

    let timeout_secs = timeout.as_secs();
    let container_name = format!("crosslink-agent-{}", agent_id);

    // Resolve host auth path for credential mounting
    let home = std::env::var("HOME").unwrap_or_else(|_| "/root".to_string());
    let host_auth = format!("{}/.claude", home);

    // Get host UID/GID for remapping (skip on Windows — Docker Desktop handles user mapping)
    let uid_gid = if cfg!(target_os = "windows") {
        None
    } else {
        let uid = Command::new("id")
            .arg("-u")
            .output()
            .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
            .unwrap_or_else(|_| "1000".to_string());
        let gid = Command::new("id")
            .arg("-g")
            .output()
            .map(|o| String::from_utf8_lossy(&o.stdout).trim().to_string())
            .unwrap_or_else(|_| "1000".to_string());
        Some((uid, gid))
    };

    let mut args = vec![
        "run".to_string(),
        "-d".to_string(),
        "--name".to_string(),
        container_name.clone(),
        // Hard-kill the container after the timeout (grace period = 10s on top)
        "--stop-timeout".to_string(),
        format!("{}", timeout_secs),
        // Mount the worktree as workspace
        "-v".to_string(),
        format!("{}:/workspaces/repo", worktree_dir.to_string_lossy()),
        // Mount credentials read-only
        "-v".to_string(),
        format!("{}:/host-auth:ro", host_auth),
        // Environment
        "-e".to_string(),
        format!("AGENT_ID={}", agent_id),
    ];

    // Pass UID/GID to container for user remapping (non-Windows only)
    if let Some((uid, gid)) = &uid_gid {
        args.extend([
            "-e".to_string(),
            format!("HOST_UID={}", uid),
            "-e".to_string(),
            format!("HOST_GID={}", gid),
        ]);
    }

    // Image and command
    args.push(image.to_string());
    args.push("bash".to_string());
    args.push("-c".to_string());
    args.push(format!(
        "cd /workspaces/repo && timeout {}s claude --model {} --allowedTools '{}' -- \"$(cat KICKOFF.md)\"",
        timeout_secs, model, allowed_tools
    ));

    let output = Command::new(runtime_cmd)
        .args(&args)
        .output()
        .with_context(|| format!("Failed to launch {} container", runtime_cmd))?;

    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr);
        bail!("{} container launch failed: {}", runtime_cmd, stderr.trim());
    }

    let container_id = String::from_utf8_lossy(&output.stdout).trim().to_string();
    Ok(container_id)
}

// E-ana tablet — kickoff run: main entry point for `crosslink kickoff run`
use anyhow::{bail, Context, Result};
use std::path::Path;

use crate::db::Database;
use crate::identity::AgentConfig;
use crate::shared_writer::SharedWriter;

use super::helpers::*;
use super::launch::*;
use super::prompt::*;
use super::types::*;

/// Main entry point: `crosslink kickoff run`.
pub fn run(
    crosslink_dir: &Path,
    db: &Database,
    writer: Option<&SharedWriter>,
    opts: &KickoffOpts,
) -> Result<()> {
    // 1. Pre-flight: validate all required external commands are present
    let preflight = if !opts.dry_run {
        Some(preflight_check(
            &opts.container,
            &opts.verify,
            crosslink_dir,
        )?)
    } else {
        None
    };

    let root = repo_root()?;
    let base_slug = slugify(opts.description);
    let slug = if base_slug.is_empty() {
        rand_hex_suffix()
    } else {
        format!("{}-{}", base_slug, rand_hex_suffix())
    };

    // 2. Create or find the issue
    let issue_id = if let Some(id) = opts.issue {
        // Verify the issue exists
        if db.get_issue(id)?.is_none() {
            bail!("Issue #{} not found", id);
        }
        id
    } else {
        // Create a new issue directly
        let id = if let Some(w) = writer {
            w.create_issue(
                db,
                opts.description,
                Some("Created by crosslink kickoff"),
                "medium",
            )?
        } else {
            db.create_issue(
                opts.description,
                Some("Created by crosslink kickoff"),
                "medium",
            )?
        };
        let label_err = if let Some(w) = writer {
            w.add_label(db, id, "feature").err()
        } else {
            db.add_label(id, "feature").err()
        };
        if let Some(e) = label_err {
            eprintln!("Warning: could not label issue #{id} with 'feature': {e}");
        }
        if !opts.quiet {
            println!("Created issue #{}", id);
        }
        id
    };

    // 3. Create worktree and feature branch (or use existing branch)
    let (worktree_dir, branch_name) = if let Some(br) = opts.branch {
        // Use existing branch — check if worktree exists
        let wt_slug = br.strip_prefix("feature/").unwrap_or(br);
        let worktree_dir = root.join(".worktrees").join(wt_slug);
        if !worktree_dir.exists() {
            create_worktree(&root, wt_slug, None)?
        } else {
            (worktree_dir, br.to_string())
        }
    } else {
        create_worktree(&root, &slug, None)?
    };

    // Write slug sentinel so other commands can identify this worktree
    std::fs::write(worktree_dir.join(".kickoff-slug"), &slug)
        .context("Failed to write .kickoff-slug sentinel")?;

    // 4. Detect project conventions
    let conventions = detect_conventions(&root);

    // 5. Build the prompt
    let prompt = build_prompt(opts, issue_id, &branch_name, &conventions);

    // 6. Write KICKOFF.md to worktree
    std::fs::write(worktree_dir.join("KICKOFF.md"), &prompt)
        .context("Failed to write KICKOFF.md")?;

    // 6b. Extract and write criteria if design doc has acceptance criteria
    if let Some(doc) = opts.design_doc {
        if !doc.acceptance_criteria.is_empty() {
            let source = opts.doc_path.unwrap_or("unknown");
            let criteria_file = extract_criteria(doc, source);
            let json = serde_json::to_string_pretty(&criteria_file)
                .context("Failed to serialize criteria")?;
            std::fs::write(worktree_dir.join(".kickoff-criteria.json"), &json)
                .context("Failed to write .kickoff-criteria.json")?;
        }
    }

    // 6c. Write launch metadata (timeout + start time) for status tracking
    {
        let metadata = KickoffMetadata {
            started_at: chrono::Utc::now().to_rfc3339(),
            timeout_secs: opts.timeout.as_secs(),
        };
        let json = serde_json::to_string_pretty(&metadata)
            .context("Failed to serialize kickoff metadata")?;
        std::fs::write(worktree_dir.join(".kickoff-metadata.json"), &json)
            .context("Failed to write .kickoff-metadata.json")?;
    }

    // 7. Exclude kickoff files from git
    exclude_kickoff_files(&worktree_dir)?;

    // Dry run: print prompt and exit (skip agent init — no launch needed)
    if opts.dry_run {
        let parent_id = AgentConfig::load(crosslink_dir)?
            .map(|c| c.agent_id)
            .unwrap_or_else(|| "driver".to_string());
        let agent_id = format!("{}--{}", parent_id, slug);
        println!("{}", prompt);
        println!("---");
        println!("Worktree: {}", worktree_dir.display());
        println!("Branch:   {}", branch_name);
        println!("Agent:    {}", agent_id);
        return Ok(());
    }

    // 8. Initialize crosslink + agent in worktree (only for real launches)
    let agent_id = init_worktree_agent(&worktree_dir, crosslink_dir, &slug)?;

    // preflight is guaranteed Some after the dry-run early return above
    let preflight = preflight.context("preflight check was skipped unexpectedly")?;

    // 9. Launch the agent
    let allowed_tools = build_allowed_tools(&conventions, &opts.verify);

    match &opts.container {
        ContainerMode::None => {
            let mut session_name = tmux_session_name(&slug);
            if tmux_session_exists(&session_name) {
                // Append random suffix
                let suffix: u32 = rand_suffix();
                session_name =
                    format!("{}-{}", &session_name[..session_name.len().min(44)], suffix);
            }

            launch_local(
                &worktree_dir,
                &session_name,
                opts.model,
                &allowed_tools,
                opts.timeout,
                preflight.timeout_cmd,
                preflight.sandbox_command.as_deref(),
                crosslink_dir,
                opts.skip_permissions,
            )?;

            // 10. Report
            if !opts.quiet {
                println!("Feature agent launched.");
                println!();
                println!("  Worktree: {}", worktree_dir.display());
                println!("  Branch:   {}", branch_name);
                println!("  Issue:    #{}", issue_id);
                println!("  Agent:    {}", agent_id);
                println!("  Session:  {}", session_name);
                println!("  Verify:   {:?}", opts.verify);
                println!();
                println!("  Approve trust:  tmux attach -t {}", session_name);
                println!("  Check status:   crosslink kickoff status {}", agent_id);
                if opts.verify == VerifyLevel::Ci || opts.verify == VerifyLevel::Thorough {
                    println!();
                    println!("  CI verification is enabled. The agent will push and open a draft PR after local tests pass.");
                }
            } else {
                println!("{}", session_name);
            }
        }
        mode @ (ContainerMode::Docker | ContainerMode::Podman) => {
            let container_id = launch_container(
                mode,
                &worktree_dir,
                opts.image,
                &agent_id,
                opts.model,
                &allowed_tools,
                opts.timeout,
            )?;

            if !opts.quiet {
                let runtime = if *mode == ContainerMode::Docker {
                    "docker"
                } else {
                    "podman"
                };
                println!("Feature agent launched in container.");
                println!();
                println!("  Worktree:    {}", worktree_dir.display());
                println!("  Branch:      {}", branch_name);
                println!("  Issue:       #{}", issue_id);
                println!("  Agent:       {}", agent_id);
                println!(
                    "  Container:   {}",
                    &container_id[..12.min(container_id.len())]
                );
                println!("  Verify:      {:?}", opts.verify);
                println!();
                println!(
                    "  View logs:   {} logs -f {}",
                    runtime,
                    &container_id[..12.min(container_id.len())]
                );
                println!("  Check status: crosslink kickoff status {}", agent_id);
            } else {
                println!("{}", container_id);
            }
        }
    }

    Ok(())
}

use anyhow::{bail, Result};

use crate::db::Database;
use crate::shared_writer::SharedWriter;
use crate::utils::format_issue_id;

const VALID_PRIORITIES: [&str; 4] = ["low", "medium", "high", "critical"];

/// Best-effort lock release: tries v2 first, then falls back to v1.
/// Mirrors the helper in `session.rs`.
fn release_lock_best_effort(crosslink_dir: &std::path::Path, issue_id: i64) {
    if let Ok(Some(agent)) = crate::identity::AgentConfig::load(crosslink_dir) {
        if let Ok(sync) = crate::sync::SyncManager::new(crosslink_dir) {
            if sync.is_initialized() {
                if sync.is_v2_layout() {
                    if let Ok(Some(writer)) = SharedWriter::new(crosslink_dir) {
                        if let Err(e) = writer.release_lock_v2(issue_id) {
                            eprintln!(
                                "Warning: Could not release lock on {}: {}",
                                format_issue_id(issue_id),
                                e
                            );
                        }
                    }
                } else if let Err(e) = sync.release_lock(&agent, issue_id, false) {
                    eprintln!(
                        "Warning: Could not release lock on {}: {}",
                        format_issue_id(issue_id),
                        e
                    );
                }
            }
        }
    }
}

/// Built-in issue templates
pub struct Template {
    pub name: &'static str,
    pub priority: &'static str,
    pub label: &'static str,
    pub description_prefix: Option<&'static str>,
}

pub const TEMPLATES: &[Template] = &[
    Template {
        name: "bug",
        priority: "high",
        label: "bug",
        description_prefix: Some("Steps to reproduce:\n1. \n\nExpected: \nActual: "),
    },
    Template {
        name: "feature",
        priority: "medium",
        label: "feature",
        description_prefix: Some("Goal: \n\nAcceptance criteria:\n- "),
    },
    Template {
        name: "refactor",
        priority: "low",
        label: "refactor",
        description_prefix: Some("Current state: \n\nDesired state: \n\nReason: "),
    },
    Template {
        name: "research",
        priority: "low",
        label: "research",
        description_prefix: Some("Question: \n\nContext: \n\nFindings: "),
    },
    Template {
        name: "audit",
        priority: "high",
        label: "audit",
        description_prefix: Some("Scope: \n\nFiles to review: \n\nFindings: \n\nSeverity: "),
    },
    Template {
        name: "continuation",
        priority: "high",
        label: "continuation",
        description_prefix: Some("Previous session: \n\nCompleted: \n\nRemaining: \n\nBlockers: "),
    },
    Template {
        name: "investigation",
        priority: "medium",
        label: "investigation",
        description_prefix: Some(
            "Symptom: \n\nReproduction: \n\nHypotheses: \n\nRoot cause: \n\nFix: ",
        ),
    },
];

pub fn get_template(name: &str) -> Option<&'static Template> {
    TEMPLATES.iter().find(|t| t.name == name)
}

pub fn list_templates() -> Vec<&'static str> {
    TEMPLATES.iter().map(|t| t.name).collect()
}

pub fn validate_priority(priority: &str) -> bool {
    VALID_PRIORITIES.contains(&priority)
}

/// Options shared by create and subissue commands.
pub struct CreateOpts<'a> {
    pub labels: &'a [String],
    pub work: bool,
    pub quiet: bool,
    /// If set, lock enforcement is checked when --work is used.
    pub crosslink_dir: Option<&'a std::path::Path>,
    /// Skip compaction after creation (batch mode — display ID assigned on next compaction).
    pub defer_id: bool,
}

pub fn run(
    db: &Database,
    writer: Option<&SharedWriter>,
    title: &str,
    description: Option<&str>,
    priority: &str,
    template: Option<&str>,
    opts: &CreateOpts<'_>,
) -> Result<()> {
    // Apply template if specified
    let (final_priority, final_description, template_label) = if let Some(tmpl_name) = template {
        let tmpl = get_template(tmpl_name).ok_or_else(|| {
            anyhow::anyhow!(
                "Unknown template '{}'. Available: {}",
                tmpl_name,
                list_templates().join(", ")
            )
        })?;

        // Template priority is default, user can override
        let priority = if priority != "medium" {
            priority
        } else {
            tmpl.priority
        };

        // Combine template description prefix with user description
        let desc = match (tmpl.description_prefix, description) {
            (Some(prefix), Some(user_desc)) => Some(format!("{}\n\n{}", prefix, user_desc)),
            (Some(prefix), None) => Some(prefix.to_string()),
            (None, user_desc) => user_desc.map(|s| s.to_string()),
        };

        (priority.to_string(), desc, Some(tmpl.label))
    } else {
        (
            priority.to_string(),
            description.map(|s| s.to_string()),
            None,
        )
    };

    if !validate_priority(&final_priority) {
        bail!(
            "Invalid priority '{}'. Must be one of: {}",
            final_priority,
            VALID_PRIORITIES.join(", ")
        );
    }

    let id = if let Some(w) = writer {
        let id = w.create_issue(db, title, final_description.as_deref(), &final_priority)?;

        // Auto-add label from template
        if let Some(lbl) = template_label {
            w.add_label(db, id, lbl)?;
        }

        // Add user-specified labels
        for lbl in opts.labels {
            w.add_label(db, id, lbl)?;
        }

        id
    } else {
        // Wrap create + labels in a transaction so a label failure
        // doesn't leave an issue without its labels.
        db.transaction(|| {
            let id = db.create_issue(title, final_description.as_deref(), &final_priority)?;

            // Auto-add label from template
            if let Some(lbl) = template_label {
                db.add_label(id, lbl)?;
            }

            // Add user-specified labels
            for lbl in opts.labels {
                db.add_label(id, lbl)?;
            }

            Ok(id)
        })?
    };

    if opts.defer_id && !opts.quiet {
        println!(
            "Created issue {} (display ID deferred — assigned on next compaction)",
            format_issue_id(id)
        );
    } else if opts.quiet {
        println!("{}", id);
    } else {
        println!("Created issue {}", format_issue_id(id));
        if let Some(tmpl) = template {
            println!("  Applied template: {}", tmpl);
        }
    }

    // Set as active session work item
    if opts.work {
        let mut freshly_claimed = false;

        // Check lock status before allowing work on this issue
        if let Some(dir) = opts.crosslink_dir {
            crate::lock_check::enforce_lock(dir, id, db)?;

            // Auto-claim lock in multi-agent mode (same as session work)
            if let Ok(Some(agent)) = crate::identity::AgentConfig::load(dir) {
                if let Ok(sync) = crate::sync::SyncManager::new(dir) {
                    if sync.is_initialized() {
                        if sync.is_v2_layout() {
                            if let Ok(Some(writer)) = SharedWriter::new(dir) {
                                match writer.claim_lock_v2(id, None) {
                                    Ok(crate::shared_writer::LockClaimResult::Claimed) => {
                                        freshly_claimed = true;
                                        if !opts.quiet {
                                            println!(
                                                "Auto-claimed lock on issue {}",
                                                format_issue_id(id)
                                            );
                                        }
                                    }
                                    Ok(crate::shared_writer::LockClaimResult::AlreadyHeld) => {}
                                    Ok(crate::shared_writer::LockClaimResult::Contended {
                                        winner_agent_id,
                                    }) => {
                                        eprintln!(
                                            "Warning: Lock on {} won by '{}'",
                                            format_issue_id(id),
                                            winner_agent_id
                                        );
                                    }
                                    Err(e) => {
                                        tracing::warn!("Could not auto-claim lock: {}", e)
                                    }
                                }
                            }
                        } else {
                            match sync.claim_lock(&agent, id, None, false) {
                                Ok(true) => {
                                    freshly_claimed = true;
                                    if !opts.quiet {
                                        println!(
                                            "Auto-claimed lock on issue {}",
                                            format_issue_id(id)
                                        );
                                    }
                                }
                                Ok(false) => {}
                                Err(e) => tracing::warn!("Could not auto-claim lock: {}", e),
                            }
                        }
                    }
                }
            }
        }
        let agent_id = opts.crosslink_dir.and_then(|dir| {
            crate::identity::AgentConfig::load(dir)
                .ok()
                .flatten()
                .map(|a| a.agent_id)
        });
        if let Ok(Some(session)) = db.get_current_session_for_agent(agent_id.as_deref()) {
            // If set_session_issue fails after we claimed a lock, release the lock
            // to avoid orphaned locks.
            if let Err(e) = db.set_session_issue(session.id, id) {
                if freshly_claimed {
                    if let Some(dir) = opts.crosslink_dir {
                        release_lock_best_effort(dir, id);
                    }
                }
                return Err(e);
            }
            if !opts.quiet {
                println!("Now working on: {} {}", format_issue_id(id), title);
            }
        } else if !opts.quiet {
            eprintln!("Warning: --work specified but no active session");
        }
    }

    Ok(())
}

pub fn run_subissue(
    db: &Database,
    writer: Option<&SharedWriter>,
    parent_id: i64,
    title: &str,
    description: Option<&str>,
    priority: &str,
    opts: &CreateOpts<'_>,
) -> Result<()> {
    if !validate_priority(priority) {
        bail!(
            "Invalid priority '{}'. Must be one of: {}",
            priority,
            VALID_PRIORITIES.join(", ")
        );
    }

    // Verify parent exists
    let parent = db.get_issue(parent_id)?;
    if parent.is_none() {
        bail!("Parent issue {} not found", format_issue_id(parent_id));
    }

    let id = if let Some(w) = writer {
        let id = w.create_subissue(db, parent_id, title, description, priority)?;

        // Add user-specified labels
        for lbl in opts.labels {
            w.add_label(db, id, lbl)?;
        }

        id
    } else {
        // Wrap create + labels in a transaction so a label failure
        // doesn't leave a subissue without its labels.
        db.transaction(|| {
            let id = db.create_subissue(parent_id, title, description, priority)?;

            // Add user-specified labels
            for lbl in opts.labels {
                db.add_label(id, lbl)?;
            }

            Ok(id)
        })?
    };

    if opts.quiet {
        println!("{}", id);
    } else {
        println!(
            "Created subissue {} under {}",
            format_issue_id(id),
            format_issue_id(parent_id)
        );
    }

    // Set as active session work item
    if opts.work {
        let mut freshly_claimed = false;

        // Check lock status before allowing work on this issue
        if let Some(dir) = opts.crosslink_dir {
            crate::lock_check::enforce_lock(dir, id, db)?;

            // Auto-claim lock in multi-agent mode (same as session work)
            if let Ok(Some(agent)) = crate::identity::AgentConfig::load(dir) {
                if let Ok(sync) = crate::sync::SyncManager::new(dir) {
                    if sync.is_initialized() {
                        if sync.is_v2_layout() {
                            if let Ok(Some(writer)) = SharedWriter::new(dir) {
                                match writer.claim_lock_v2(id, None) {
                                    Ok(crate::shared_writer::LockClaimResult::Claimed) => {
                                        freshly_claimed = true;
                                        if !opts.quiet {
                                            println!(
                                                "Auto-claimed lock on issue {}",
                                                format_issue_id(id)
                                            );
                                        }
                                    }
                                    Ok(crate::shared_writer::LockClaimResult::AlreadyHeld) => {}
                                    Ok(crate::shared_writer::LockClaimResult::Contended {
                                        winner_agent_id,
                                    }) => {
                                        eprintln!(
                                            "Warning: Lock on {} won by '{}'",
                                            format_issue_id(id),
                                            winner_agent_id
                                        );
                                    }
                                    Err(e) => {
                                        tracing::warn!("Could not auto-claim lock: {}", e)
                                    }
                                }
                            }
                        } else {
                            match sync.claim_lock(&agent, id, None, false) {
                                Ok(true) => {
                                    freshly_claimed = true;
                                    if !opts.quiet {
                                        println!(
                                            "Auto-claimed lock on issue {}",
                                            format_issue_id(id)
                                        );
                                    }
                                }
                                Ok(false) => {}
                                Err(e) => tracing::warn!("Could not auto-claim lock: {}", e),
                            }
                        }
                    }
                }
            }
        }
        let agent_id = opts.crosslink_dir.and_then(|dir| {
            crate::identity::AgentConfig::load(dir)
                .ok()
                .flatten()
                .map(|a| a.agent_id)
        });
        if let Ok(Some(session)) = db.get_current_session_for_agent(agent_id.as_deref()) {
            // If set_session_issue fails after we claimed a lock, release the lock
            // to avoid orphaned locks.
            if let Err(e) = db.set_session_issue(session.id, id) {
                if freshly_claimed {
                    if let Some(dir) = opts.crosslink_dir {
                        release_lock_best_effort(dir, id);
                    }
                }
                return Err(e);
            }
            if !opts.quiet {
                println!("Now working on: {} {}", format_issue_id(id), title);
            }
        } else if !opts.quiet {
            eprintln!("Warning: --work specified but no active session");
        }
    }

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use proptest::prelude::*;

    // ==================== Unit Tests ====================

    #[test]
    fn test_validate_priority_valid() {
        assert!(validate_priority("low"));
        assert!(validate_priority("medium"));
        assert!(validate_priority("high"));
        assert!(validate_priority("critical"));
    }

    #[test]
    fn test_validate_priority_invalid() {
        assert!(!validate_priority(""));
        assert!(!validate_priority("urgent"));
        assert!(!validate_priority("LOW")); // Case sensitive
        assert!(!validate_priority("MEDIUM"));
        assert!(!validate_priority("High"));
        assert!(!validate_priority("CRITICAL"));
        assert!(!validate_priority(" medium"));
        assert!(!validate_priority("medium "));
        assert!(!validate_priority("medium\n"));
    }

    #[test]
    fn test_validate_priority_malicious() {
        // Security: ensure no injection vectors
        assert!(!validate_priority("'; DROP TABLE issues; --"));
        assert!(!validate_priority("high\0medium"));
        assert!(!validate_priority("medium; DELETE FROM issues"));
        assert!(!validate_priority("<script>alert('xss')</script>"));
    }

    #[test]
    fn test_get_template_exists() {
        let bug = get_template("bug");
        assert!(bug.is_some());
        let template = bug.unwrap();
        assert_eq!(template.name, "bug");
        assert_eq!(template.priority, "high");
        assert_eq!(template.label, "bug");
        assert!(template.description_prefix.is_some());
    }

    #[test]
    fn test_get_template_not_found() {
        assert!(get_template("nonexistent").is_none());
        assert!(get_template("").is_none());
        assert!(get_template("Bug").is_none()); // Case sensitive
        assert!(get_template("BUG").is_none());
    }

    #[test]
    fn test_list_templates() {
        let templates = list_templates();
        assert!(templates.contains(&"bug"));
        assert!(templates.contains(&"feature"));
        assert!(templates.contains(&"refactor"));
        assert!(templates.contains(&"research"));
        assert!(templates.contains(&"audit"));
        assert!(templates.contains(&"continuation"));
        assert!(templates.contains(&"investigation"));
        assert_eq!(templates.len(), 7);
    }

    #[test]
    fn test_template_fields() {
        // Verify all templates have required fields
        for template in TEMPLATES {
            assert!(!template.name.is_empty());
            assert!(validate_priority(template.priority));
            assert!(!template.label.is_empty());
        }
    }

    #[test]
    fn test_template_bug_description_prefix() {
        let template = get_template("bug").unwrap();
        let prefix = template.description_prefix.unwrap();
        assert!(prefix.contains("Steps to reproduce"));
        assert!(prefix.contains("Expected"));
        assert!(prefix.contains("Actual"));
    }

    #[test]
    fn test_template_feature_description_prefix() {
        let template = get_template("feature").unwrap();
        let prefix = template.description_prefix.unwrap();
        assert!(prefix.contains("Goal"));
        assert!(prefix.contains("Acceptance criteria"));
    }

    // ==================== Property-Based Tests ====================

    proptest! {
        #[test]
        fn prop_invalid_priorities_never_validate(
            priority in "[a-zA-Z]{1,20}"
                .prop_filter("Exclude valid priorities", |s| {
                    !["low", "medium", "high", "critical"].contains(&s.as_str())
                })
        ) {
            prop_assert!(!validate_priority(&priority));
        }

        #[test]
        fn prop_unknown_template_returns_none(name in "[a-zA-Z]{5,20}"
            .prop_filter("Exclude known templates", |s| {
                !["bug", "feature", "refactor", "research", "audit", "continuation", "investigation"].contains(&s.as_str())
            })
        ) {
